/**
 * Parses user-provided text for LinkedIn profile URLs and simple name/title lines.
 * Does not call LinkedIn servers or scrape pages (against LinkedIn ToS).
 */
const LINKEDIN_PROFILE =
  /https?:\/\/(?:[\w.-]+\.)?linkedin\.com\/(?:in|pub)\/([^/?#\s]+)/gi;

export type ParsedLead = {
  profileUrl: string;
  slug: string;
  name?: string;
  headline?: string;
  company?: string;
  location?: string;
  sourceRaw: string;
};

function normalizeUrl(match: string): string {
  try {
    const u = new URL(match);
    u.hash = "";
    u.search = "";
    return u.toString();
  } catch {
    return match;
  }
}

function titleCaseFromSlug(slug: string): string {
  return slug
    .replace(/[-_]+/g, " ")
    .replace(/\b\w/g, (c) => c.toUpperCase());
}

/** Extract bullet-style "Name · Role · Company" segments from pasted snippets */
function parseStructuredLine(line: string): Partial<ParsedLead> | null {
  const trimmed = line.trim();
  if (!trimmed || trimmed.startsWith("http")) return null;
  const parts = trimmed.split("·").map((p) => p.trim());
  if (parts.length < 2) return null;
  return {
    name: parts[0] || undefined,
    headline: parts[1] || undefined,
    company: parts[2] || undefined,
    location: parts[3] || undefined,
  };
}

export function parseLinkedInPaste(blob: string): ParsedLead[] {
  const lines = blob.split(/\r?\n/).map((l) => l.trim());
  const byUrl = new Map<string, ParsedLead>();

  for (const line of lines) {
    LINKEDIN_PROFILE.lastIndex = 0;
    let m: RegExpExecArray | null;
    while ((m = LINKEDIN_PROFILE.exec(line)) !== null) {
      const full = m[0];
      const slug = decodeURIComponent(m[1] ?? "").replace(/\/$/, "");
      const profileUrl = normalizeUrl(full);
      const structured = parseStructuredLine(line.replace(full, "").trim());
      const existing = byUrl.get(profileUrl);
      const name =
        structured?.name ??
        existing?.name ??
        (slug ? titleCaseFromSlug(slug) : undefined);
      byUrl.set(profileUrl, {
        profileUrl,
        slug,
        name,
        headline: structured?.headline ?? existing?.headline,
        company: structured?.company ?? existing?.company,
        location: structured?.location ?? existing?.location,
        sourceRaw: line,
      });
    }
  }

  if (byUrl.size > 0) return [...byUrl.values()];

  LINKEDIN_PROFILE.lastIndex = 0;
  let m: RegExpExecArray | null;
  while ((m = LINKEDIN_PROFILE.exec(blob)) !== null) {
    const full = m[0];
    const slug = decodeURIComponent(m[1] ?? "").replace(/\/$/, "");
    const profileUrl = normalizeUrl(full);
    if (!byUrl.has(profileUrl)) {
      byUrl.set(profileUrl, {
        profileUrl,
        slug,
        name: titleCaseFromSlug(slug),
        sourceRaw: full,
      });
    }
  }

  return [...byUrl.values()];
}

export function parseCsv(text: string): Record<string, string>[] {
  const rows: string[][] = [];
  let cur = "";
  let row: string[] = [];
  let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i]!;
    if (inQuotes) {
      if (c === '"') {
        if (text[i + 1] === '"') {
          cur += '"';
          i++;
        } else {
          inQuotes = false;
        }
      } else {
        cur += c;
      }
    } else {
      if (c === '"') inQuotes = true;
      else if (c === ",") {
        row.push(cur);
        cur = "";
      } else if (c === "\n" || c === "\r") {
        if (c === "\r" && text[i + 1] === "\n") i++;
        row.push(cur);
        rows.push(row);
        row = [];
        cur = "";
      } else {
        cur += c;
      }
    }
  }
  row.push(cur);
  rows.push(row);

  const header = rows[0]?.map((h) => h.trim().toLowerCase()) ?? [];
  const out: Record<string, string>[] = [];
  for (let r = 1; r < rows.length; r++) {
    const cells = rows[r] ?? [];
    if (cells.every((c) => !c.trim())) continue;
    const obj: Record<string, string> = {};
    header.forEach((key, idx) => {
      obj[key] = (cells[idx] ?? "").trim();
    });
    out.push(obj);
  }
  return out;
}

/** Map loose CSV column names to our fields */
export function rowToLead(row: Record<string, string>): ParsedLead {
  const keys = Object.keys(row);
  const find = (...candidates: string[]) => {
    for (const c of candidates) {
      const k = keys.find((x) => x.includes(c));
      if (k && row[k]) return row[k];
    }
    return "";
  };
  const profileUrl =
    find("url", "linkedin", "profile") ||
    [...Object.values(row)].find((v) => /linkedin\.com\/in\//i.test(v)) ||
    "";
  const name = find("name", "full name", "first") || row[keys[0]!] || "";
  return {
    profileUrl: profileUrl || "https://linkedin.com/in/unknown",
    slug: profileUrl.split("/in/")[1]?.split(/[/?]/)[0] || "unknown",
    name: name || undefined,
    headline: find("headline", "title", "job", "position"),
    company: find("company", "organization", "employer"),
    location: find("location", "city", "region"),
    sourceRaw: JSON.stringify(row),
  };
}

import * as XLSX from "xlsx";

export type BuyerRow = {
  name: string;
  headline?: string;
  company?: string;
  location?: string;
  profileUrl?: string;
  email?: string;
  notes?: string;
  createdAt?: string;
};

export function downloadBuyersExcel(buyers: BuyerRow[], filename = "buyers.xlsx") {
  const sheet = XLSX.utils.json_to_sheet(
    buyers.map((b) => ({
      Name: b.name,
      Headline: b.headline ?? "",
      Company: b.company ?? "",
      Location: b.location ?? "",
      "Profile URL": b.profileUrl ?? "",
      Email: b.email ?? "",
      Notes: b.notes ?? "",
      "Created at": b.createdAt ?? "",
    })),
  );
  const book = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(book, sheet, "Buyers");
  XLSX.writeFile(book, filename);
}

