import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import { Amplify } from "aws-amplify";
import outputs from "../amplify_outputs.json";
import App from "./App";
import "./index.css";
import "@aws-amplify/ui-react/styles.css";

Amplify.configure(outputs);

createRoot(document.getElementById("root")!).render(
  <StrictMode>
    <App />
  </StrictMode>,
);

import { useCallback, useEffect, useMemo, useState } from "react";
import { Authenticator } from "@aws-amplify/ui-react";
import { generateClient } from "aws-amplify/data";
import type { Schema } from "../amplify/data/resource";
import { parseCsv, parseLinkedInPaste, rowToLead } from "./lib/parseLinkedIn";
import { downloadBuyersExcel } from "./lib/excelExport";
import "./App.css";

const client = generateClient<Schema>();

type BuyerRecord = Schema["Buyer"]["type"];

function AppContent() {
  const [paste, setPaste] = useState("");
  const [buyers, setBuyers] = useState<BuyerRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const refresh = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const { data, errors } = await client.models.Buyer.list();
      if (errors?.length) {
        setError(errors.map((e) => e.message).join("; "));
        return;
      }
      setBuyers([...(data ?? [])].sort((a, b) => {
        const ta = a.createdAt ?? "";
        const tb = b.createdAt ?? "";
        return tb.localeCompare(ta);
      }));
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    void refresh();
  }, [refresh]);

  const parsedPreview = useMemo(() => parseLinkedInPaste(paste), [paste]);

  const importFromPaste = async () => {
    setMessage(null);
    setError(null);
    const leads = parseLinkedInPaste(paste);
    if (!leads.length) {
      setMessage("No LinkedIn profile URLs found. Paste URLs or lines like: Name · Title · Company");
      return;
    }
    setLoading(true);
    try {
      for (const lead of leads) {
        await client.models.Buyer.create({
          name: lead.name ?? lead.slug,
          headline: lead.headline,
          company: lead.company,
          location: lead.location,
          profileUrl: lead.profileUrl,
          sourceRaw: lead.sourceRaw,
        });
      }
      setPaste("");
      setMessage(`Saved ${leads.length} buyer(s).`);
      await refresh();
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
    }
  };

  const onCsvFile = async (file: File | null) => {
    if (!file) return;
    setMessage(null);
    setError(null);
    const text = await file.text();
    const rows = parseCsv(text);
    if (!rows.length) {
      setMessage("CSV had no data rows.");
      return;
    }
    setLoading(true);
    try {
      let n = 0;
      for (const row of rows) {
        const lead = rowToLead(row);
        await client.models.Buyer.create({
          name: lead.name || lead.slug || "Imported buyer",
          headline: lead.headline,
          company: lead.company,
          location: lead.location,
          profileUrl: lead.profileUrl || undefined,
          sourceRaw: lead.sourceRaw,
        });
        n++;
      }
      setMessage(`Imported ${n} row(s) from CSV.`);
      await refresh();
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
    }
  };

  const exportExcel = () => {
    downloadBuyersExcel(
      buyers.map((b) => ({
        name: b.name,
        headline: b.headline ?? undefined,
        company: b.company ?? undefined,
        location: b.location ?? undefined,
        profileUrl: b.profileUrl ?? undefined,
        email: b.email ?? undefined,
        notes: b.notes ?? undefined,
        createdAt: b.createdAt ?? undefined,
      })),
      `buyers-${new Date().toISOString().slice(0, 10)}.xlsx`,
    );
    setMessage("Download started.");
  };

  const remove = async (id: string) => {
    setError(null);
    try {
      await client.models.Buyer.delete({ id });
      await refresh();
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    }
  };

  return (
    <div className="shell">
      <header className="hero">
        <h1>Buyer leads</h1>
        <p className="lede">
          Capture contacts from pasted LinkedIn snippets or CSV, sync with AWS Amplify Data, and export to Excel.
          This app does not scrape LinkedIn; use data you are allowed to use (for example your own exports or pasted
          profile links).
        </p>
      </header>

      {message && <div className="banner ok">{message}</div>}
      {error && <div className="banner err">{error}</div>}

      <section className="card">
        <h2>Paste LinkedIn URLs or snippets</h2>
        <textarea
          className="paste"
          value={paste}
          onChange={(e) => setPaste(e.target.value)}
          placeholder="Example:&#10;https://www.linkedin.com/in/jane-doe&#10;Jane Doe · VP Sales · Acme · London"
          rows={6}
        />
        <div className="row">
          <button type="button" className="primary" disabled={loading} onClick={() => void importFromPaste()}>
            Save parsed leads
          </button>
          <span className="muted">{parsedPreview.length} URL(s) detected</span>
        </div>
      </section>

      <section className="card">
        <h2>Import CSV</h2>
        <p className="muted small">
          Columns like name, headline, company, location, url / linkedin are detected automatically.
        </p>
        <input
          type="file"
          accept=".csv,text/csv"
          disabled={loading}
          onChange={(e) => void onCsvFile(e.target.files?.[0] ?? null)}
        />
      </section>

      <section className="card">
        <div className="row spread">
          <h2>Your buyers ({buyers.length})</h2>
          <div className="row">
            <button type="button" className="ghost" disabled={loading} onClick={() => void refresh()}>
              Refresh
            </button>
            <button type="button" className="primary" disabled={!buyers.length} onClick={exportExcel}>
              Download Excel
            </button>
          </div>
        </div>
        {loading && <p className="muted">Loading…</p>}
        {!loading && buyers.length === 0 && <p className="muted">No buyers yet.</p>}
        {buyers.length > 0 && (
          <div className="table-wrap">
            <table className="grid">
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Headline</th>
                  <th>Company</th>
                  <th>Profile</th>
                  <th />
                </tr>
              </thead>
              <tbody>
                {buyers.map((b) => (
                  <tr key={b.id}>
                    <td>{b.name}</td>
                    <td>{b.headline}</td>
                    <td>{b.company}</td>
                    <td>
                      {b.profileUrl ? (
                        <a href={b.profileUrl} target="_blank" rel="noreferrer">
                          Open
                        </a>
                      ) : (
                        "—"
                      )}
                    </td>
                    <td>
                      <button type="button" className="linkish" onClick={() => void remove(b.id)}>
                        Remove
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>
    </div>
  );
}

export default function App() {
  return (
    <Authenticator>
      <AppContent />
    </Authenticator>
  );
}

